/* temporary local stub for development; replace with official sheetjs build before production */
(function (global) {
  function csvToRows(text) {
    return String(text || '')
      .split(/\r?\n/)
      .filter(Boolean)
      .map(function (line) {
        return line.split(',').map(function (cell) {
          return cell.trim()
        })
      })
  }

  global.XLSX = {
    read: function (buffer) {
      var text = ''
      try {
        text = new TextDecoder().decode(buffer)
      } catch (_error) {
        text = ''
      }
      return {
        SheetNames: ['Sheet1'],
        Sheets: {
          Sheet1: { __rows: csvToRows(text) },
        },
      }
    },
    utils: {
      sheet_to_json: function (sheet) {
        return sheet && Array.isArray(sheet.__rows) ? sheet.__rows : []
      },
    },
  }
})(globalThis)
